import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, User, Edit, Search, MapPin } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtists = () => {
  const [artists, setArtists] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtists();
      const actualData = res.data?.data || [];
      setArtists(Array.isArray(actualData) ? actualData : []);
    } catch (err) {
      setArtists([]);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm("Permanent Archive Deletion?")) return;
    try {
      await AdminService.deleteArtist(id);
      toast.success("Record Deleted");
      fetchData(); // Refresh list
    } catch (err) {
      toast.error("Delete Failed");
    }
  };

  const filtered = artists.filter(a => 
    a.Full_Name?.toLowerCase().includes(search.toLowerCase()) || 
    a.Artist_ID?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase italic">Archive <span className="text-primary">Artists</span></h1>
        </div>
        <Link to="/admin/artists/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-primary transition-all">
          <Plus size={16} /> Register Artist
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
        <input 
          placeholder="Search Registry..." 
          className="w-full bg-white/5 border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.map((artist: any) => (
          <div key={artist._id} className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 group">
            <div className="flex items-center gap-6 mb-6">
              <div className="w-20 h-20 bg-white/5 rounded-2xl flex items-center justify-center overflow-hidden border border-white/10">
                {/* LOGIC: Fallback Image 1 -> Image 2 -> Icon */}
                {artist.Cloudinary_Image1 || artist.Cloudinary_Image2 ? (
                  <img 
                    src={artist.Cloudinary_Image1 || artist.Cloudinary_Image2} 
                    className="w-full h-full object-cover" 
                    alt="" 
                  />
                ) : (
                  <User size={30} className="text-gray-700" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <span className="text-[9px] bg-primary/20 text-primary px-2 py-0.5 rounded font-black mb-1 inline-block">{artist.Artist_ID}</span>
                <h4 className="font-black uppercase text-sm italic truncate text-white">{artist.Full_Name}</h4>
                <p className="text-[10px] font-bold text-gray-500 uppercase">{artist.Birth_Country || 'Global'}</p>
              </div>
            </div>
            
            <div className="grid grid-cols-2 gap-2">
              <Link to={`/admin/artists/edit/${artist.Artist_ID}`} className="py-3 bg-white/5 rounded-xl font-black text-[9px] uppercase text-center text-white hover:bg-white hover:text-black transition-all">Modify</Link>
              <button 
                onClick={() => handleDelete(artist.Artist_ID)}
                className="py-3 bg-red-500/10 text-red-500 rounded-xl font-black text-[9px] uppercase hover:bg-red-500 hover:text-white transition-all"
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
